import heapq

class AğırlıklıGrafik:
    def __init__(self):
        self.komşuluk_listesi = {}

    def kenar_ekle(self, düğüm1, düğüm2, ağırlık):
        if düğüm1 not in self.komşuluk_listesi:
            self.komşuluk_listesi[düğüm1] = []
        if düğüm2 not in self.komşuluk_listesi:
            self.komşuluk_listesi[düğüm2] = []

        self.komşuluk_listesi[düğüm1].append((düğüm2, ağırlık))
        self.komşuluk_listesi[düğüm2].append((düğüm1, ağırlık))  # Eğer grafik yönlü ise bu satırı kaldırın.

    def dijkstra(self, başlangıç_düğümü):
        mesafeler = {düğüm: float('inf') for düğüm in self.komşuluk_listesi}
        mesafeler[başlangıç_düğümü] = 0
        kuyruk = [(0, başlangıç_düğümü)]  # (mesafe, düğüm)

        while kuyruk:
            mesafe, mevcut_düğüm = heapq.heappop(kuyruk)

            if mesafe > mesafeler[mevcut_düğüm]:
                continue

            if mevcut_düğüm in self.komşuluk_listesi:
                for komşu, ağırlık in self.komşuluk_listesi[mevcut_düğüm]:
                    yeni_mesafe = mesafe + ağırlık
                    if yeni_mesafe < mesafeler[komşu]:
                        mesafeler[komşu] = yeni_mesafe
                        heapq.heappush(kuyruk, (yeni_mesafe, komşu))

        return mesafeler

if __name__ == '__main__':
    # Örnek kullanım:
    grafik = AğırlıklıGrafik()
    grafik.kenar_ekle('A', 'B', 4)
    grafik.kenar_ekle('A', 'C', 2)
    grafik.kenar_ekle('B', 'C', 5)
    grafik.kenar_ekle('B', 'D', 10)
    grafik.kenar_ekle('C', 'E', 3)
    grafik.kenar_ekle('D', 'F', 11)
    grafik.kenar_ekle('E', 'D', 4)

    başlangıç_düğümü = 'A'
    en_kısa_mesafeler = grafik.dijkstra(başlangıç_düğümü)

    print(f"Başlangıç Düğümü: {başlangıç_düğümü}")
    for düğüm, mesafe in en_kısa_mesafeler.items():
        print(f"{düğüm}: {mesafe}")
